import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Allocate a buffer of appropriate size based on user input length
        byte[] buffer = new byte[userInput.length()];

        // Perform bounds checking to prevent buffer overflow
        int copyLength = Math.min(userInput.length(), buffer.length);

        // Copy user input to buffer using safer approach
        for (int i = 0; i < copyLength; i++) {
            buffer[i] = (byte) userInput.charAt(i);
        }

        System.out.println("User input copied to buffer successfully.");
    }
}

